import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getChainHealthScore(chainName) {
  const [activity, gas] = await Promise.all([
    client.BaseService.getAllChains(),
    client.BaseService.getGasPrices(chainName, "eip1559"),
  ]);
  const chain = activity.data?.items?.find(c => c.name === chainName);
  return {
    chainName,
    blockHeight: chain?.block_signed_at,
    gasPrice: gas.data?.items?.[0]?.gas_price,
  };
}
